var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"찰나의 순간.","JPN":"刹那の瞬間。","ENG":"In a fleeting moment.","TWN":"刹那的瞬間。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"죽음을 앞둔 찰나의 순간, 인간은 시간이 느려지는 듯한 경험을 한다고 한다.","JPN":"死を目前にしたその瞬間、人は時の流れが遅くなる感覚を覚えるらしい。","ENG":"They say, in the moment before death, time seems to slow for humans.","TWN":"在瀕臨死亡的瞬間，人類會感到時間似乎變慢了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"자, 잘 부탁드립니다, 선배님들!","JPN":"よ、よろしくお願いします、先輩方！","ENG":"P-pleased to meet you all!","TWN":"那麼，請多關照，各位前輩！"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L5_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"부족하지만 최선을 다해, 여러분들의 힘이 되도록 노력하겠습니다!","JPN":"未熟ですが、一生懸命皆さんの力になれるように頑張ります！","ENG":"I may not be much, but I'll do my best to support you all!","TWN":"雖然能力有限，但我會盡力成為大家的助力！"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"응? 열두 가문 출신이 아닌 게 뭐 어때서?","JPN":"うん？　12家門出身じゃないって、それがどうかした？","ENG":"Huh? So what if you're not from one of the Twelve Houses?","TWN":"嗯？不是十二家族出身有什麼問題？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"BATTLE_NORMAL_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L7_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"단장은 우리 중에 제일 강하고 믿음직스럽잖아. 그럼 된 거지, 뭐!","JPN":"団長は私たちの中で一番強くて頼もしいんだよ。それでいいんだって！","ENG":"Captain's the strongest and most reliable among us. That's all that matters!","TWN":"團長是我們中最強大、最值得信賴的人。這就夠了，不是嗎！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"BATTLE_NORMAL_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"저는 아직 몸도 약하고 다른 분들처럼 싸울 수는 없지만…….","JPN":"私はまだ体も弱いですし、皆さんのようには戦えないですけど……","ENG":"I'm still not strong like the others...","TWN":"我現在身體還很弱，雖然不能像其他人那樣戰鬥……"},"stage":{"bg":"FALL_PARK","bgm":"BATTLE_NORMAL_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L9_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"그래도, 나중에는 꼭 멋진 기사가 될 거예요! 단장님 같은 멋진 기사요!!","JPN":"でも、大きくなったら立派な騎士になります！　団長のようにカッコいい騎士に！！","ENG":"But one day, I'll become a real knight just like you, Captain!","TWN":"不過，將來我一定會成為一名出色的騎士！像團長你一樣出色的騎士！！"},"stage":{"bg":"FALL_PARK","bgm":"BATTLE_NORMAL_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"narration","speaker":null,"text":{"KOREA":"동료들의 발걸음 소리가 멀어짐에 침식체와의 간극이 좁혀지는 순간이 다가오고.","JPN":"仲間たちの足音が遠くなるにつれ、侵食体との距離が近くなる瞬間が来る。","ENG":"The moment draws near. The gap between the C.O.s and the retreating footsteps of comrades closes.","TWN":"同伴們的腳步聲漸漸遠去，與侵蝕體的距離逐漸縮短的時刻即將到來。"},"stage":{"bg":"BLACK","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"narration","speaker":null,"text":{"KOREA":"첨예한 발톱이 눈앞을 가르지만, 그럼에도 주변 풍경은 흘러가듯 지나간다.","JPN":"鋭い爪が目の前を横切るが、それでも周りの風景は流れるように過ぎて行く。","ENG":"Claws slash through the air, but the world still flows past in slow motion.","TWN":"鋒利的爪子劃過眼前，但周圍的景色依然如流水般逝去。"},"stage":{"bg":"BLACK","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"단장님과 침식체가 격돌합니다!","JPN":"団長と侵食体が激突します！","ENG":"Captain's clashing with the C.O.!","TWN":"團長與侵蝕體正面交鋒！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"제길. 지원을 하기에는 거리가…!!","JPN":"くそ。支援するには距離が……！！","ENG":"Damn it, we're too far to provide backup...!","TWN":"可惡。支援的距離……！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"narration","speaker":null,"text":{"KOREA":"두려움은 없다.","JPN":"恐怖はない。","ENG":"There's no fear.","TWN":"沒有恐懼了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"narration","speaker":null,"text":{"KOREA":"그렇기에 계속하여 나아간다.","JPN":"だから、進み続けられる。","ENG":"And so, I press forward.","TWN":"因此繼續前進。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"에스테로사 경. 부단장으로 저를 선임하는 것은 재고해 주시길 바랍니다.","JPN":"エステロサ卿。副団長として私を選任することは考え直してください。","ENG":"Dame Esterosa. Please reconsider appointing me as deputy.","TWN":"艾斯特洛索。請重新考慮任命我為副團長的決定。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"BATTLE_NORMAL_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"저는 가문에서도 재능이 없는 편이에요. 제가 부단장을 맡아서는 기사단에 폐를 끼칠 겁니다.","JPN":"私は家門の中でも才能がない方です。私が副団長になっては、騎士団の迷惑になります。","ENG":"Even among my family, I was never the gifted one. If I take the role, I'll only be a burden to the Order.","TWN":"我在家族中也算是沒什麼才能的人。如果讓我擔任副團長，會給騎士團帶來麻煩的。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"BATTLE_NORMAL_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"재능이 없음에도 이전 작전에서 시민을 구하기 위해 내 뒤에 바짝 따라붙더군.","JPN":"才能がないにも関わらず、この前の作戦では市民を助けるために私の後ろにぴったりついて来ていたな。","ENG":"Yet in the last mission, I remember you stuck right behind me to save the civilians.","TWN":"雖然沒有才能，但在之前的作戰中，為了拯救市民緊緊跟在我後面。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"BATTLE_NORMAL_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"피오네 경. 단장이 기사단을 이끈다면 부단장은 그런 단장을 보좌하는 자리야.","JPN":"フィオネ卿。団長が騎士団を率いるなら、副団長はその団長を補佐する。","ENG":"Fione, the deputy's role is to support the captain, no matter what.","TWN":"喔，菲奧尼卿。如果團長領導騎士團，那麼副團長就是輔佐這樣的團長的位置。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"BATTLE_NORMAL_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그대라면 언젠가 내가 벽에 가로막혔을 때…….","JPN":"君なら、いつか私が壁の前で立ち止まることになった時……","ENG":"And I believe that if I ever hit a wall someday...","TWN":"如果是你的話，總有一天我被牆阻擋的時候……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"BATTLE_NORMAL_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"내 곁에서 앞길을 뚫어줄 것이라 믿고 있네.","JPN":"私のそばで道を開けてくれると信じている。","ENG":"You'll be the one standing beside me, cutting a path forward.","TWN":"我相信你會在我身邊為我開闢前路。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"BATTLE_NORMAL_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"닿아라…!","JPN":"届け……！","ENG":"Strike true...!","TWN":"觸碰吧…！"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ONLY_PIONE_SKILL_START"},{"id":"L37_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"이번에야말로…!!","JPN":"今度こそ……！！","ENG":"This time for sure...!!","TWN":"這一次，絕對要……！！"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"부, 부단장님의 스콜피오 랜스가 변했어?","JPN":"ふ、副団長のスコルピオランスが変わった？","ENG":"D-Deputy's Scorpio Lance just changed form?!","TWN":"副，副團長的天蠍長槍變形了？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"날려버려, 부단장–––!!","JPN":"ぶっ飛ばして、副団長―――！！","ENG":"Let them have it, Deputy–––!!","TWN":"幹掉他們，副團長——！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"달리세요, 단장님–––––!!","JPN":"走ってください、団長―――――！！","ENG":"Go, Captain–––––!!","TWN":"快跑，團長–––––！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};